    global _instance
    if _instance is None:
        raise RuntimeError(
            'Synthesized TTNN module requires `build(device, torch_module)`. '
            'Call it from the PCC test\'s `_build_ttnn_port`.'
        )
    return _instance(*args, **kwargs)
